  // Verifica se já é um array
  if (Array.isArray(rawData)) {
    dataArray = rawData;
  }
  // Se for uma string, tenta fazer o parse
  else if (typeof rawData === 'string') {
    const parsedData = JSON.parse(rawData);
    // Verifica se o resultado do parse é realmente um array
    if (Array.isArray(parsedData)) {
      dataArray = parsedData;
    } else {
      // Opcional: Logar que o parse funcionou mas não resultou em array
      console.warn("Dados parseados de string não são um array:", parsedData);
      // Mantém dataArray como []
    }
  }
  // Opcional: Lidar com outros tipos?
  // else if (rawData != null) {
  //   // Tratar um valor único (não-array, não-string) como um array de um elemento?
  //   dataArray = [rawData];
  // }

} catch (error) {
  // Captura erros do JSON.parse (string inválida) ou outros inesperados
  console.error("Erro ao processar ou parsear os dados:", error, "Dados originais:", rawData);
  // Em caso de erro, dataArray continua sendo o array vazio definido no início
}

// Garante que só vai juntar elementos não nulos/undefined (segurança extra)
const conversation = dataArray.filter(item => item != null).join(" ");

