  agente = 'vendedor';
}

// calcula o novo estado a ser salvo
let novo;
if (agente === 'objecao') {
  // objecao nao e um estado "fixo": guardamos vendedor para nao regredir
  novo = 'vendedor';
} else if (agente === 'vendedor') {
  novo = 'vendedor';
} else {
  // so chega aqui se est === 'saudacao' e agente === 'saudacao'
  novo = 'saudacao';
}

return [{ json: {
  agente,
  novo_estado: novo,
  estado_anterior: est,
  motivo: parsed.motivo
} }];

