// recebe o item da mensagem que acabou de ser enviada
const texto = $('Loop Over Items').first().json.text || '';
const final = $json.final;

// formula: 1 segundo base + 35ms por caractere
const BASE_MS = 1000;
const MS_POR_CHAR = 35;
const MIN_MS = 2000;
const MAX_MS = 12000;

let espera = BASE_MS + (texto.length * MS_POR_CHAR);
espera = Math.max(MIN_MS, Math.min(MAX_MS, espera));

// se for a ultima mensagem do lote, nao precisa esperar
// (ja terminou de "digitar", pode soltar imediato pro proximo passo)
if (final === true) {
  espera = 0;
}

return [{
  json: {
    text: texto,
    final: final,
    espera_ms: espera,
    espera_s: Math.round(espera / 100) / 10  // pra debug, em segundos com 1 casa
  }
}];

